  ('retired-8b44517b-moex-00080', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政組織之敘述，下列何者正確？', '["獨立機關是指依據法令獨立行使職權之機關", "政府與人民合資經營之事業，皆為公營事業", "依據公法所設立之組織體，皆為公法社團", "國家任務性質上不適宜由行政機關實施亦不適宜由民間實施者，得設立行政法人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00081', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政機關管轄權之敘述，下列何者正確？', '["行政機關不得透過行政規則或與其他機關簽訂契約來變更管轄權", "無管轄權之行政機關所作成之行政處分，均為無效", "人民不服財政部中區國稅局依法所為指定管轄之決定時，得向財政部提起訴願", "經濟部依法公告委託高雄市政府辦理高雄港區內工廠設立許可、登記、管理及輔導事項，為權 限委任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00082', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '依司法實務見解，關於公務員免職權限之敘述，下列何者正確？', '["公務員之免職為法院專屬權限", "行政機關以考績處分免除公務員之職務，牴觸憲法由司法院執掌懲戒權之規定", "公務員之免職權屬於行政機關人事權之固有核心", "對於公務員違法失職之行為，行政機關不得以考績處分處罰之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00083', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '依公務員服務法規定，關於公務員於法定工作時間以外之活動，下列敘述何者正確？', '["公務員應經服務機關同意，始得兼任經常營利性質之領證職業", "公務員應經服務機關同意，始得使用職稱發表與其服務機關業務職掌有關之言論", "公務員應經服務機關同意，始得依個人才藝表現，獲取適當報酬", "公務員應經服務機關同意，始得兼任無報酬且未影響本職之研究工作 13720、30120"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00084', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於公務員懲戒之敘述，下列何者正確？', '["退休（職、伍）之公務員於任職期間之違法失職行為，仍得予以懲戒", "公務員經受免除職務之懲戒者，其停止任用期間為10年以下", "懲戒法庭應本於書面而為判決，必要時得行言詞辯論", "同一行為已受刑罰之處罰者，不得予以懲戒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00085', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於法規命令之敘述，下列何者錯誤？', '["法規名稱為「細則」、「標準」者，通常屬於法規命令", "法規命令之訂定，為行政機關職權，人民不得提議為之", "主管機關擬訂法規命令時，如因情況急迫，顯然無法事先公告周知者，得不於政府公報或新聞 紙進行公告程序", "法規命令依法應經上級機關核定者，應於上級機關核定後，始可發布"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00086', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政規則之敘述，下列何者正確？', '["行政規則係規範機關內部秩序及運作之規定", "為協助下級機關或屬官統一解釋法令、認定事實、及行使裁量權，而訂頒之解釋性規定及裁量 基準，具有直接對外效力", "行政機關訂定行政規則，依法應舉行聽證", "行政規則僅能由原發布機關之上級機關廢止之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00087', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政處分之敘述，下列何者錯誤？', '["行政處分違背法規有關專屬管轄之規定，該處分並非無效，故相對人僅得請求撤銷", "行政機關經聽證後作成之行政處分，如人民不服該處分，得直接向行政法院提起訴訟", "行政機關作成書面之行政處分，應送達處分之相對人及已知之利害關係人", "行政處分有誤寫誤繕之顯然錯誤時，原處分機關得依職權隨時更正"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00088', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '行政機關以行政處分核准甲一筆補助款，嗣後發現甲根本不符合申請資格。關於行政機關取回補 助款之敘述，下列何者正確？', '["因甲違法取得補助款，行政機關撤銷行政處分無須考量其信賴是否值得保護", "行政機關得與甲簽訂和解契約，約定分期給付之條件", "行政機關得以行政處分命甲返還受領之補助款", "甲若拒絕返還補助款，行政機關應向行政法院提起一般給付之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00089', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '現行菸害防制法規定各級學校內全面禁菸，某公立大學乃公告「配合菸害防制法之修正施行，本 校即日起撤除吸菸室／區」，該公告之法律性質為何？', '["該公告未直接限制師生吸菸之權利，並非行政處分", "該公告重申法律規定內涵，屬於觀念通知", "該公告涉及公物之一般使用方式，構成一般處分", "該公告規範對象為校內外所有人，屬於大學之自治規章"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL)
